      method: 'POST',
      headers: {
        'Authorization': `Bearer ${token}`
      },
      body: formData
    });
    const data = await response.json();
    if (!response.ok) {
      throw new Error(data.error || 'Erro ao fazer upload');
    }
    return {
      success: true,
      data
    };
  } catch (error) {
    console.error('Upload de Excel falhou:', error);
    return {
      success: false,
      error: error.message
    };
  }
}

